+import { $internal } from '../common';
+import { isRelation } from '../relation/utils/is-relation';
+import type { Schema } from '../storage';
+import type { Trait, TraitRecord, TraitValue } from './types';
+
+let aspectId = 0;
+
+export type Aspect<TTraits extends readonly Trait[] = readonly Trait[]> = {
+    readonly id: number;
+    readonly traits: TTraits;
+    readonly schema: Schema;
+    [$internal]: { fields: Map<string, Trait> };
+};
+
+export type AspectRecord<T extends Aspect> = T extends Aspect<infer Traits>
+    ? UnionToIntersection<TraitRecord<Traits[number]>>
+    : never;
+
+export type AspectValue<T extends Aspect> = Partial<AspectRecord<T>>;
+
+type UnionToIntersection<U> = (U extends any ? (value: U) => void : never) extends (
+    value: infer I
+) => void
+    ? I
+    : never;
+
+export function isAspect(value: unknown): value is Aspect {
+    return !!(value as Aspect | undefined)?.[$internal]?.fields;
+}
+
+export function createAspect<TTraits extends readonly [Trait, Trait, ...Trait[]]>(
+    ...inputs: TTraits
+): Aspect<TTraits> {
+    const traits: Trait[] = [];
+    for (const input of inputs) {
+        if (isAspect(input)) traits.push(...input.traits);
+        else traits.push(input);
+    }
+
+    const fields = new Map<string, Trait>();
+    const schema: Record<string, unknown> = {};
+    for (const trait of traits) {
+        if (isRelation(trait) || trait[$internal].relation) {
+            throw new Error('Aspects cannot contain relations');
+        }
+        for (const field of Object.keys(trait.schema)) {
+            if (fields.has(field)) {
+                throw new Error(`Aspect traits cannot share the field "${field}"`);
+            }
+            fields.set(field, trait);
+            schema[field] = (trait.schema as Record<string, unknown>)[field];
+        }
+    }
+
+    return Object.freeze({
+        id: aspectId++,
+        traits: Object.freeze(traits) as unknown as TTraits,
+        schema: Object.freeze(schema) as Schema,
+        [$internal]: { fields },
+    }) as Aspect<TTraits>;
+}
+
+export function splitAspectValue(aspect: Aspect, value: Record<string, unknown> = {}) {
+    const values = new Map<Trait, Record<string, unknown>>();
+    for (const trait of aspect.traits) values.set(trait, {});
+    for (const field in value) {
+        const trait = aspect[$internal].fields.get(field);
+        if (trait) values.get(trait)![field] = value[field];
+    }
+    return values;
+}
